import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for annotations inside TypeArgumentList.
 * See https://github.com/pinterest/ktlint/issues/673
 */
class AnnotationRuleTypeArgumentListTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Given multiple annotations inside TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given multiple annotations with parameters inside TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            val aProperty: Map<@Ann("test") @Ann2("test2") Int, @JvmSuppressWildcards(true) (String) -> Int?>
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given multiple annotations inside multiline TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            val bProperty: Map<
                @Ann @Ann2 String,
                @Ann("test") @Ann2 Int,
                @JvmSuppressWildcards(true) @Ann (String) -> Int?
                >
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotation with parameter followed by annotation without parameter inside TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            fun doSomething() {
                funWithGenericsCall<@JvmSuppressWildcards(true) @Foo Int>()
            }
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotation without parameter followed by annotation with parameter inside TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            fun doSomething() {
                funWithGenericsCall<@Foo @JvmSuppressWildcards(true) Int>()
            }
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given complex type with multiple annotations inside TypeArgumentList should not be placed on separate line`() {
        val code =
            """
            val complexProperty: SomeCustomTypeWithGenerics<
                @Foo @FooBarLongDescription @Bar1 @Bar2 SimpleDto,
                @Foo @FooBarLongDescription LongerButReasonableDto,
                @Suppress("AnnotationRule") @Foo @FooBarLongDescription ExtremeLooooooooooooooooooooooooooooongDto,
            >
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

